SELECT count(*) FROM name, cast_info, aka_name, role_type, title, movie_companies, company_name WHERE cast_info.person_id = name.id AND aka_name.person_id = name.id AND cast_info.role_id = role_type.id AND cast_info.movie_id = title.id AND movie_companies.movie_id = title.id AND movie_companies.company_id = company_name.id;